scripts.script:
function price() {
  var out = []
  var v = 2400
  for (var i = 0; i < 60; i++) {
    v += (Math.sin(i / 5) * 60) + (i * 8) - 10
    out.push([i, Math.round(v)])
  }
  return out
}

vanilla-js-script:
var toggle = document.getElementById('oc-toggle')
var on = false
toggle.addEventListener('click', function () {
  on = !on
  if (on) { chart.startMeasure(); toggle.classList.add('active') }
  else { chart.stopMeasure(); toggle.classList.remove('active') }
})
